-- Seed data generated from src/lib/seed.ts for the Plebi MVP.
-- Safe to re-run: records are upserted using deterministic UUIDs.

create extension if not exists "pgcrypto";

create or replace function public.plebi_seed_uuid(value text)
returns uuid
language sql
immutable
as $$
  select (
    substr(md5(value), 1, 8) || '-' ||
    substr(md5(value), 9, 4) || '-' ||
    substr(md5(value), 13, 4) || '-' ||
    substr(md5(value), 17, 4) || '-' ||
    substr(md5(value), 21, 12)
  )::uuid;
$$;

on conflict (slug) do update set
  name = excluded.name,
  description = excluded.description,
  subcategories = excluded.subcategories,
  signal = excluded.signal,
  benchmark = excluded.benchmark;

on conflict (id) do update set
  name = excluded.name,
  type = excluded.type,
  url = excluded.url,
  weight = excluded.weight,
  credibility = excluded.credibility;

on conflict (slug) do update set
  name = excluded.name,
  category_id = excluded.category_id,
  subcategory = excluded.subcategory,
  tagline = excluded.tagline,
  summary = excluded.summary,
  best_for = excluded.best_for,
  website = excluded.website,
  pricing = excluded.pricing,
  founded = excluded.founded,
  stage = excluded.stage,
  metrics = excluded.metrics;

on conflict (id) do update set
  tool_id = excluded.tool_id,
  source_id = excluded.source_id,
  title = excluded.title,
  observed_at = excluded.observed_at,
  score = excluded.score,
  confidence = excluded.confidence,
  metric_impacts = excluded.metric_impacts,
  notes = excluded.notes;

on conflict (id) do update set
  tool_id = excluded.tool_id,
  captured_at = excluded.captured_at,
  score = excluded.score,
  reason = excluded.reason;

on conflict (tool_id) do update set
  votes_for = excluded.votes_for,
  votes_against = excluded.votes_against;

drop function if exists public.plebi_seed_uuid(text);

